const orderId = $fromAI('order_id', 'ID de la orden');
const validationCode = $fromAI('validation_code', 'Código validador');
const domain = $env.APP_DOMAIN;
if (!orderId || !validationCode) return { error: 'Se necesitan orderId y validationCode.' };
const link = `${domain}/order/${orderId}?token=${validationCode}`;
return { trackingLink: link, message: `🔍 Sigue tu pedido aquí: ${link}` };

// ✅ ANTI-BAN: Procesar output del agente
// 1. Detectar [SESIÓN_CERRADA]
// 2. Calcular delay humanizado aleatorio
const rawOutput = $json.output || '';
const shouldClose = rawOutput.includes('[SESIÓN_CERRADA]');
const cleanText = rawOutput.replace('[SESIÓN_CERRADA]', '').trim();

const minMs = parseInt($env.WA_TYPING_MIN_S || '1') * 1000;
const maxMs = parseInt($env.WA_TYPING_MAX_S || '4') * 1000;
const delay = Math.floor(Math.random() * (maxMs - minMs) + minMs);

const phone = $('When Executed by Another Workflow').first().json.phone;
const sessionData = $('When Executed by Another Workflow').first().json.sessionData || {};

return [{ json: { cleanText, shouldClose, phone, delay, sessionData, orderId: sessionData.orderId } }];

// Mensaje de fallback con delay humanizado
const minMs = parseInt($env.WA_TYPING_MIN_S || '1') * 1000;
const maxMs = parseInt($env.WA_TYPING_MAX_S || '3') * 1000;
const delay = Math.floor(Math.random() * (maxMs - minMs) + minMs);
const phone = $('When Executed by Another Workflow').first().json.phone;
return [{ json: { phone, delay, cleanText: 'Lo sentimos, ocurrió un error procesando tu solicitud. Un asesor te contactará pronto. 🙏' } }];

// Actualizar lastActivity en la sesión
const phone = $json.phone;
const sessionData = $json.sessionData || {};
sessionData.lastActivity = new Date().toISOString();
return [{ json: { phone, updatedSession: JSON.stringify(sessionData) } }];
